patch:
Index: backend/templates/index.html
===================================================================
--- backend/templates/index.html	
+++ backend/templates/index.html	
@@ -0,0 +1,582 @@
+<!DOCTYPE html>
+<html lang="pt-BR">
+<head>
+    <meta charset="UTF-8">
+    <meta name="viewport" content="width=device-width, initial-scale=1.0, maximum-scale=1.0, user-scalable=no">
+    <title>RDC // Downloads</title>
+    <link rel="preconnect" href="https://fonts.googleapis.com">
+    <link href="https://fonts.googleapis.com/css2?family=Orbitron:wght@400;700;900&family=Rajdhani:wght@300;500;700&family=Share+Tech+Mono&display=swap" rel="stylesheet">
+    <style>
+        * { margin: 0; padding: 0; box-sizing: border-box; }
+
+        :root {
+            --cyan: #00f0ff;
+            --magenta: #ff00de;
+            --purple: #b000ff;
+            --dark: #0a0a12;
+            --panel: rgba(10, 10, 18, 0.85);
+            --border-glow: rgba(0, 240, 255, 0.3);
+        }
+
+        body {
+            font-family: 'Rajdhani', sans-serif;
+            background: var(--dark);
+            color: #c8c8d4;
+            min-height: 100vh;
+            min-height: 100dvh;
+            overflow-x: hidden;
+            position: relative;
+        }
+
+        body::before {
+            content: '';
+            position: fixed;
+            inset: 0;
+            background:
+                url('https://images.unsplash.com/photo-1526374965328-7f61d4dc18c5?auto=format&fit=crop&w=1920&q=80') center/cover no-repeat;
+            opacity: 0.12;
+            z-index: 0;
+            pointer-events: none;
+        }
+
+        body::after {
+            content: '';
+            position: fixed;
+            inset: 0;
+            background:
+                linear-gradient(180deg, rgba(10,10,18,0.3) 0%, transparent 30%, transparent 70%, rgba(10,10,18,0.6) 100%),
+                repeating-linear-gradient(0deg, transparent, transparent 2px, rgba(0,240,255,0.015) 2px, rgba(0,240,255,0.015) 4px);
+            z-index: 1;
+            pointer-events: none;
+            animation: scanlines 8s linear infinite;
+        }
+
+        @keyframes scanlines {
+            0% { background-position: 0 0; }
+            100% { background-position: 0 100px; }
+        }
+
+        @keyframes flicker {
+            0%, 95%, 100% { opacity: 1; }
+            96% { opacity: 0.8; }
+            97% { opacity: 1; }
+            98% { opacity: 0.6; }
+        }
+
+        @keyframes glitchShift {
+            0%, 100% { transform: translate(0); }
+            20% { transform: translate(-2px, 1px); }
+            40% { transform: translate(2px, -1px); }
+            60% { transform: translate(-1px, -1px); }
+            80% { transform: translate(1px, 2px); }
+        }
+
+        @keyframes borderPulse {
+            0%, 100% { border-color: rgba(0, 240, 255, 0.2); box-shadow: 0 0 10px rgba(0,240,255,0.05); }
+            50% { border-color: rgba(0, 240, 255, 0.5); box-shadow: 0 0 20px rgba(0,240,255,0.15); }
+        }
+
+        @keyframes neonPulse {
+            0%, 100% { text-shadow: 0 0 10px var(--cyan), 0 0 40px rgba(0,240,255,0.3); }
+            50% { text-shadow: 0 0 20px var(--cyan), 0 0 60px rgba(0,240,255,0.5); }
+        }
+
+        @keyframes float {
+            0%, 100% { transform: translateY(0); }
+            50% { transform: translateY(-6px); }
+        }
+
+        .main-wrapper {
+            position: relative;
+            z-index: 2;
+            min-height: 100vh;
+            min-height: 100dvh;
+            display: flex;
+            flex-direction: column;
+            padding: 20px;
+        }
+
+        .top-bar {
+            display: flex;
+            justify-content: space-between;
+            align-items: center;
+            padding: 12px 16px;
+            background: var(--panel);
+            border: 1px solid var(--border-glow);
+            border-radius: 8px;
+            margin-bottom: 24px;
+            backdrop-filter: blur(10px);
+        }
+
+        .top-bar .brand {
+            font-family: 'Orbitron', sans-serif;
+            font-size: 0.75rem;
+            font-weight: 900;
+            color: var(--cyan);
+            letter-spacing: 4px;
+            text-transform: uppercase;
+        }
+
+        .top-bar .status {
+            font-family: 'Share Tech Mono', monospace;
+            font-size: 0.65rem;
+            color: rgba(0, 240, 255, 0.6);
+        }
+
+        .status-dot {
+            display: inline-block;
+            width: 6px;
+            height: 6px;
+            background: #00ff88;
+            border-radius: 50%;
+            margin-right: 6px;
+            animation: neonPulse 2s ease-in-out infinite;
+            box-shadow: 0 0 6px #00ff88;
+        }
+
+        .hero {
+            text-align: center;
+            padding: 30px 10px;
+            margin-bottom: 20px;
+        }
+
+        .hero h1 {
+            font-family: 'Orbitron', sans-serif;
+            font-size: clamp(1.8rem, 6vw, 3rem);
+            font-weight: 900;
+            color: #fff;
+            text-transform: uppercase;
+            letter-spacing: 3px;
+            animation: neonPulse 3s ease-in-out infinite, flicker 4s infinite;
+            position: relative;
+        }
+
+        .hero h1::after {
+            content: attr(data-text);
+            position: absolute;
+            left: 2px;
+            top: 0;
+            color: var(--magenta);
+            opacity: 0;
+            clip-path: inset(0 0 0 0);
+            animation: glitchClip 5s infinite;
+        }
+
+        @keyframes glitchClip {
+            0%, 90%, 100% { clip-path: inset(0 100% 0 0); opacity: 0; }
+            92% { clip-path: inset(20% 0 60% 0); opacity: 0.7; transform: translate(-3px, 1px); }
+            94% { clip-path: inset(60% 0 10% 0); opacity: 0.7; transform: translate(3px, -1px); }
+            96% { clip-path: inset(40% 0 30% 0); opacity: 0.7; transform: translate(-2px, 0); }
+        }
+
+        .hero .tagline {
+            font-family: 'Share Tech Mono', monospace;
+            font-size: 0.85rem;
+            color: rgba(0, 240, 255, 0.5);
+            margin-top: 12px;
+            letter-spacing: 2px;
+        }
+
+        .info-grid {
+            display: grid;
+            grid-template-columns: repeat(2, 1fr);
+            gap: 12px;
+            margin-bottom: 24px;
+        }
+
+        .info-card {
+            background: var(--panel);
+            border: 1px solid rgba(176, 0, 255, 0.2);
+            border-radius: 10px;
+            padding: 16px 12px;
+            text-align: center;
+            backdrop-filter: blur(10px);
+            transition: all 0.3s;
+            animation: borderPulse 4s ease-in-out infinite;
+        }
+
+        .info-card:nth-child(2) { animation-delay: 0.5s; }
+        .info-card:nth-child(3) { animation-delay: 1s; }
+        .info-card:nth-child(4) { animation-delay: 1.5s; }
+
+        .info-card:hover {
+            border-color: var(--magenta);
+            transform: translateY(-3px);
+            box-shadow: 0 8px 30px rgba(255, 0, 222, 0.15);
+        }
+
+        .info-card .icon {
+            font-size: 1.6rem;
+            margin-bottom: 6px;
+            display: block;
+        }
+
+        .info-card .label {
+            font-family: 'Share Tech Mono', monospace;
+            font-size: 0.6rem;
+            color: rgba(0, 240, 255, 0.5);
+            text-transform: uppercase;
+            letter-spacing: 2px;
+            margin-bottom: 4px;
+        }
+
+        .info-card .value {
+            font-family: 'Orbitron', sans-serif;
+            font-size: 1rem;
+            font-weight: 700;
+            color: #fff;
+        }
+
+        .download-section {
+            background: var(--panel);
+            border: 1px solid var(--border-glow);
+            border-radius: 12px;
+            padding: 24px 20px;
+            margin-bottom: 24px;
+            backdrop-filter: blur(10px);
+        }
+
+        .section-header {
+            display: flex;
+            align-items: center;
+            gap: 10px;
+            margin-bottom: 20px;
+            padding-bottom: 12px;
+            border-bottom: 1px solid rgba(0, 240, 255, 0.1);
+        }
+
+        .section-header .hex-icon {
+            width: 36px;
+            height: 36px;
+            background: linear-gradient(135deg, var(--cyan), var(--purple));
+            clip-path: polygon(50% 0%, 100% 25%, 100% 75%, 50% 100%, 0% 75%, 0% 25%);
+            display: flex;
+            align-items: center;
+            justify-content: center;
+            font-size: 0.9rem;
+        }
+
+        .section-header h2 {
+            font-family: 'Orbitron', sans-serif;
+            font-size: 0.85rem;
+            font-weight: 700;
+            color: var(--cyan);
+            letter-spacing: 2px;
+            text-transform: uppercase;
+        }
+
+        .file-list { list-style: none; }
+
+        .file-item {
+            background: rgba(0, 240, 255, 0.03);
+            border: 1px solid rgba(0, 240, 255, 0.08);
+            border-radius: 10px;
+            padding: 14px 16px;
+            margin-bottom: 10px;
+            display: flex;
+            align-items: center;
+            justify-content: space-between;
+            transition: all 0.3s;
+            position: relative;
+            overflow: hidden;
+        }
+
+        .file-item::before {
+            content: '';
+            position: absolute;
+            left: 0;
+            top: 0;
+            bottom: 0;
+            width: 3px;
+            background: linear-gradient(180deg, var(--cyan), var(--magenta));
+            opacity: 0;
+            transition: opacity 0.3s;
+        }
+
+        .file-item:hover {
+            border-color: var(--cyan);
+            background: rgba(0, 240, 255, 0.06);
+            transform: translateX(4px);
+        }
+
+        .file-item:hover::before { opacity: 1; }
+
+        .file-info {
+            display: flex;
+            align-items: center;
+            gap: 12px;
+            min-width: 0;
+            flex: 1;
+        }
+
+        .file-icon-wrapper {
+            width: 38px;
+            height: 38px;
+            background: linear-gradient(135deg, rgba(0,240,255,0.15), rgba(176,0,255,0.15));
+            border-radius: 8px;
+            display: flex;
+            align-items: center;
+            justify-content: center;
+            font-size: 1.1rem;
+            flex-shrink: 0;
+            border: 1px solid rgba(0, 240, 255, 0.2);
+        }
+
+        .file-details { min-width: 0; }
+
+        .file-name {
+            font-family: 'Share Tech Mono', monospace;
+            font-size: 0.8rem;
+            color: #e0e0e8;
+            white-space: nowrap;
+            overflow: hidden;
+            text-overflow: ellipsis;
+        }
+
+        .file-meta {
+            font-size: 0.65rem;
+            color: rgba(0, 240, 255, 0.4);
+            margin-top: 2px;
+            font-family: 'Share Tech Mono', monospace;
+        }
+
+        .download-btn {
+            background: linear-gradient(135deg, var(--cyan), var(--purple));
+            color: #000;
+            border: none;
+            padding: 8px 18px;
+            border-radius: 6px;
+            cursor: pointer;
+            text-decoration: none;
+            font-family: 'Orbitron', sans-serif;
+            font-size: 0.65rem;
+            font-weight: 700;
+            letter-spacing: 1px;
+            text-transform: uppercase;
+            transition: all 0.3s;
+            flex-shrink: 0;
+            margin-left: 12px;
+        }
+
+        .download-btn:hover {
+            box-shadow: 0 0 20px rgba(0, 240, 255, 0.5), 0 0 40px rgba(176, 0, 255, 0.3);
+            transform: scale(1.05);
+        }
+
+        .download-btn:active {
+            transform: scale(0.97);
+        }
+
+        .empty-state {
+            text-align: center;
+            padding: 40px 20px;
+        }
+
+        .empty-state .empty-icon {
+            font-size: 2.5rem;
+            margin-bottom: 12px;
+            animation: float 3s ease-in-out infinite;
+        }
+
+        .empty-state p {
+            font-family: 'Share Tech Mono', monospace;
+            font-size: 0.8rem;
+            color: rgba(200, 200, 212, 0.4);
+            letter-spacing: 1px;
+        }
+
+        .features {
+            display: grid;
+            grid-template-columns: 1fr;
+            gap: 10px;
+            margin-bottom: 24px;
+        }
+
+        .feature-item {
+            background: var(--panel);
+            border: 1px solid rgba(255, 0, 222, 0.15);
+            border-radius: 10px;
+            padding: 14px 16px;
+            display: flex;
+            align-items: center;
+            gap: 12px;
+            backdrop-filter: blur(10px);
+            transition: all 0.3s;
+        }
+
+        .feature-item:hover {
+            border-color: var(--magenta);
+            transform: translateX(4px);
+        }
+
+        .feature-icon {
+            width: 32px;
+            height: 32px;
+            background: rgba(255, 0, 222, 0.1);
+            border-radius: 50%;
+            display: flex;
+            align-items: center;
+            justify-content: center;
+            font-size: 0.9rem;
+            flex-shrink: 0;
+        }
+
+        .feature-text .feat-title {
+            font-family: 'Orbitron', sans-serif;
+            font-size: 0.7rem;
+            font-weight: 700;
+            color: #fff;
+            letter-spacing: 1px;
+        }
+
+        .feature-text .feat-desc {
+            font-size: 0.7rem;
+            color: rgba(200, 200, 212, 0.5);
+            margin-top: 2px;
+        }
+
+        .footer {
+            margin-top: auto;
+            padding-top: 20px;
+            text-align: center;
+            border-top: 1px solid rgba(0, 240, 255, 0.08);
+        }
+
+        .footer p {
+            font-family: 'Share Tech Mono', monospace;
+            font-size: 0.6rem;
+            color: rgba(200, 200, 212, 0.25);
+            letter-spacing: 2px;
+        }
+
+        .footer .cyber-line {
+            width: 60px;
+            height: 2px;
+            background: linear-gradient(90deg, transparent, var(--cyan), transparent);
+            margin: 10px auto;
+        }
+
+        .corner-decor {
+            position: fixed;
+            width: 40px;
+            height: 40px;
+            border: 2px solid rgba(0, 240, 255, 0.15);
+            z-index: 3;
+            pointer-events: none;
+        }
+
+        .corner-decor.tl { top: 10px; left: 10px; border-right: none; border-bottom: none; }
+        .corner-decor.tr { top: 10px; right: 10px; border-left: none; border-bottom: none; }
+        .corner-decor.bl { bottom: 10px; left: 10px; border-right: none; border-top: none; }
+        .corner-decor.br { bottom: 10px; right: 10px; border-left: none; border-top: none; }
+
+        @media (min-width: 600px) {
+            .main-wrapper { padding: 30px 40px; }
+            .info-grid { grid-template-columns: repeat(4, 1fr); }
+            .features { grid-template-columns: repeat(3, 1fr); }
+        }
+
+        @media (min-width: 900px) {
+            .main-wrapper { max-width: 900px; margin: 0 auto; padding: 40px; }
+        }
+    </style>
+</head>
+<body>
+    <div class="corner-decor tl"></div>
+    <div class="corner-decor tr"></div>
+    <div class="corner-decor bl"></div>
+    <div class="corner-decor br"></div>
+
+    <div class="main-wrapper">
+        <div class="top-bar">
+            <span class="brand">RDC</span>
+            <span class="status"><span class="status-dot"></span>SYSTEM ONLINE</span>
+        </div>
+
+        <div class="hero">
+            <h1 data-text="DOWNLOADS">DOWNLOADS</h1>
+            <p class="tagline">// CENTRAL DE INSTALADORES v2.0</p>
+        </div>
+
+        <div class="info-grid">
+            <div class="info-card">
+                <span class="icon">&#128187;</span>
+                <div class="label">Plataforma</div>
+                <div class="value">Windows</div>
+            </div>
+            <div class="info-card">
+                <span class="icon">&#128274;</span>
+                <div class="label">Seguranca</div>
+                <div class="value">100%</div>
+            </div>
+            <div class="info-card">
+                <span class="icon">&#9889;</span>
+                <div class="label">Velocidade</div>
+                <div class="value">5G</div>
+            </div>
+            <div class="info-card">
+                <span class="icon">&#128640;</span>
+                <div class="label">Versao</div>
+                <div class="value">2.0</div>
+            </div>
+        </div>
+
+        <div class="download-section">
+            <div class="section-header">
+                <div class="hex-icon">&#128229;</div>
+                <h2>Arquivos Disponiveis</h2>
+            </div>
+            {% if files %}
+            <ul class="file-list">
+                {% for file in files %}
+                <li class="file-item">
+                    <div class="file-info">
+                        <div class="file-icon-wrapper">&#128196;</div>
+                        <div class="file-details">
+                            <div class="file-name">{{ file }}</div>
+                            <div class="file-meta">INSTALADOR // VERIFICADO</div>
+                        </div>
+                    </div>
+                    <a href="/download/{{ file }}" class="download-btn">Baixar</a>
+                </li>
+                {% endfor %}
+            </ul>
+            {% else %}
+            <div class="empty-state">
+                <div class="empty-icon">&#128204;</div>
+                <p>NENHUM ARQUIVO DISPONIVEL</p>
+            </div>
+            {% endif %}
+        </div>
+
+        <div class="features">
+            <div class="feature-item">
+                <div class="feature-icon">&#128737;</div>
+                <div class="feature-text">
+                    <div class="feat-title">Instalacao Segura</div>
+                    <div class="feat-desc">Verificado e livre de malware</div>
+                </div>
+            </div>
+            <div class="feature-item">
+                <div class="feature-icon">&#128260;</div>
+                <div class="feature-text">
+                    <div class="feat-title">Atualizacoes Automaticas</div>
+                    <div class="feat-desc">Sempre na versao mais recente</div>
+                </div>
+            </div>
+            <div class="feature-item">
+                <div class="feature-icon">&#127760;</div>
+                <div class="feature-text">
+                    <div class="feat-title">Suporte 24/7</div>
+                    <div class="feat-desc">Assistencia completa</div>
+                </div>
+            </div>
+        </div>
+
+        <div class="footer">
+            <div class="cyber-line"></div>
+            <p>RDC SYSTEMS // 2026</p>
+        </div>
+    </div>
+</body>
+</html>
